//! Axum query string extractor using serde_qs for bracket notation.
//! Supports JSON:API-style `?filter[field]=value` parameters.
//! Generated by codegraph. DO NOT EDIT.

use axum::extract::FromRequestParts;
use axum::http::request::Parts;
use axum::http::StatusCode;
use axum::response::{IntoResponse, Response};
use percent_encoding::percent_decode_str;
use serde::de::DeserializeOwned;

/// Drop-in replacement for `axum::extract::Query` that uses `serde_qs`
/// so bracket-notation keys like `filter[worker_id]=value` are correctly
/// deserialized into nested structs / HashMaps.
pub struct QsQuery<T>(pub T);

#[derive(Debug)]
pub struct QsQueryRejection(String);

impl std::fmt::Display for QsQueryRejection {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Invalid query string: {}", self.0)
    }
}

impl IntoResponse for QsQueryRejection {
    fn into_response(self) -> Response {
        (StatusCode::BAD_REQUEST, self.0).into_response()
    }
}

impl<S, T> FromRequestParts<S> for QsQuery<T>
where
    S: Send + Sync,
    T: DeserializeOwned,
{
    type Rejection = QsQueryRejection;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let raw = parts.uri.query().unwrap_or_default();
        // Percent-decode the query string so bracket notation (e.g.
        // `filter%5Bworker_id%5D=value`) is interpreted by serde_qs.
        let decoded = percent_decode_str(raw).decode_utf8_lossy();
        let value: T =
            serde_qs::from_str(&decoded).map_err(|e| QsQueryRejection(e.to_string()))?;
        Ok(QsQuery(value))
    }
}
